 1	import React, { FC, useState } from 'react';
 2	import produce from 'immer';
 3	import { isDeschedulerOn } from 'src/views/templates/utils/utils';
 4	
 5	import VirtualMachineDescriptionItem from '@kubevirt-utils/components/VirtualMachineDescriptionItem/VirtualMachineDescriptionItem';
 6	import { documentationURL } from '@kubevirt-utils/constants/documentation';
 7	import { useDeschedulerInstalled } from '@kubevirt-utils/hooks/useDeschedulerInstalled';
 8	import { useIsAdmin } from '@kubevirt-utils/hooks/useIsAdmin';
 9	import { useKubevirtTranslation } from '@kubevirt-utils/hooks/useKubevirtTranslation';
10	import { V1Template } from '@kubevirt-utils/models';
11	import { getTemplateVirtualMachineObject } from '@kubevirt-utils/resources/template';
12	import { DESCHEDULER_EVICT_LABEL } from '@kubevirt-utils/resources/vmi';
13	import { ensurePath } from '@kubevirt-utils/utils/utils';
14	import { Button, Switch } from '@patternfly/react-core';
15	import { ExternalLinkAltIcon } from '@patternfly/react-icons';
16	
17	type DeschedulerProps = {
18	  onSubmit?: (updatedTemplate: V1Template) => Promise<V1Template | void>;
19	  template: V1Template;
20	};
21	
22	const Descheduler: FC<DeschedulerProps> = ({ onSubmit, template }) => {
23	  const { t } = useKubevirtTranslation();
24	  const isDeschedulerInstalled = useDeschedulerInstalled();
25	  const isAdmin = useIsAdmin();
26	  const [isChecked, setIsChecked] = useState<boolean>(isDeschedulerOn(template));
27	  const isDeschedulerEnabled = isAdmin && isDeschedulerInstalled;
28	
29	  const updatedDeschedulerTemplate = (checked: boolean) => {
30	    return produce<V1Template>(template, (draft: V1Template) => {
31	      const draftVM = getTemplateVirtualMachineObject(draft);
32	      ensurePath(draftVM, 'spec.template.metadata.annotations');
33	      if (!draftVM.spec.template.metadata.annotations)
34	        draftVM.spec.template.metadata.annotations = {};
35	      if (checked) {
36	        draftVM.spec.template.metadata.annotations[DESCHEDULER_EVICT_LABEL] = 'true';
37	      } else {
38	        delete draftVM.spec.template.metadata.annotations[DESCHEDULER_EVICT_LABEL];
39	      }
40	      onSubmit(draft);
41	    });
42	  };
43	  return (
44	    <>
45	      <VirtualMachineDescriptionItem
46	        bodyContent={
47	          <>
48	            {t(
49	              'The Descheduler can be used to evict a running VirtualMachine so that the VirtualMachine can be rescheduled onto a more suitable Node via a live migration.',
50	            )}
51	            <div className="margin-top">
52	              <Button
53	                className="no-left-padding"
54	                component="a"
55	                href={documentationURL.DESCHEDULER}
56	                icon={<ExternalLinkAltIcon />}
57	                iconPosition="right"
58	                target="_blank"
59	                variant="link"
60	              >
61	                {t('Learn more')}
62	              </Button>
63	            </div>
64	          </>
65	        }
66	        descriptionData={
67	          <Switch
68	            onChange={(_event, checked) => {
69	              setIsChecked(checked);
70	              updatedDeschedulerTemplate(checked);
71	            }}
72	            id="descheduler-switch"
73	            isChecked={isChecked}
74	            isDisabled={!isDeschedulerEnabled}
75	          />
76	        }
77	        descriptionHeader={t('Descheduler')}
78	        isPopover
79	      />
80	    </>
81	  );
82	};
83	
84	export default Descheduler;

